    private fun ASTNode.isPrimaryConstructorAnnotation() =
        takeIf { elementType == ANNOTATION_ENTRY }
            ?.takeIf { it.treeParent.elementType == MODIFIER_LIST }
            ?.treeParent
            ?.takeIf { it.treeParent.elementType == PRIMARY_CONSTRUCTOR }
            .let { it != null }

    private fun visitPrimaryConstructorAnnotation(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        val expectedIndent = getNewlineWithIndent(node.treeParent).plus(indentConfig.indent)
        if (node.isFirstAnnotationEntry()) {
            // Annotation before constructor should be on separate line from class identifier:
            //    data class Foo @Bar1 constructor()
            // should be formatted as:
            //    data class Foo
            //        @Bar1
            //        constructor()
            node
                .firstChildLeafOrSelf()
                .prevLeaf()
                ?.takeIf { it.elementType == WHITE_SPACE && !it.textContains('\n') }
                ?.let {
                    emit(node.startOffset, "Expected newline before annotation", true)
                    if (autoCorrect) {
                        node.firstChildLeafOrSelf().upsertWhitespaceBeforeMe(expectedIndent)
                    }
                }
        }
        if (node.isFollowedByOtherAnnotationEntryOnTheSameLine()) {
            // Each annotation should be on a separate line:
            //    data class Foo @Bar1 @Bar2 constructor()
            // should be formatted as:
            //    data class Foo
            //        @Bar1
            //        @Bar2
            //        constructor()
            emit(node.startOffset, "Expected each annotation to be on a separate line", true)
            if (autoCorrect) {
                node.lastChildLeafOrSelf().nextLeaf()?.upsertWhitespaceBeforeMe(expectedIndent)
            }
        }
        if (node.isLastAnnotationEntry()) {
            // Last annotation should be on separate line from constructor keyword:
            //    data class Foo @Bar1 constructor()
            // should be formatted as:
            //    data class Foo
            //        @Bar1
            //        constructor()
            node
                .treeParent
                .treeParent
                .findChildByType(CONSTRUCTOR_KEYWORD)
                ?.let { constructorKeyword ->
                    val prevLeaf = constructorKeyword.prevLeaf()
                    if (prevLeaf?.elementType == WHITE_SPACE && !prevLeaf.textContains('\n')) {
                        emit(constructorKeyword.startOffset, "Expected newline before 'constructor' keyword", true)
                        if (autoCorrect) {
                            constructorKeyword.upsertWhitespaceBeforeMe(expectedIndent)
                        }
                    }
                }
        }
    }

