    private fun getNewlineWithIndentForPrimaryConstructorAnnotation(node: ASTNode): String {
        // For primary constructor annotations, the indent should be computed from the CLASS element
        // node.treeParent = MODIFIER_LIST
        // node.treeParent.treeParent = PRIMARY_CONSTRUCTOR
        // node.treeParent.treeParent.treeParent = CLASS
        val classNode =
            node
                .treeParent
                .treeParent
                .treeParent
        val nodeBeforeClass = classNode.treePrev
        // Make sure we only insert a single newline
        val classIndent =
            nodeBeforeClass
                ?.text
                .orEmpty()
                .substringAfterLast('\n')
        return "\n".plus(classIndent).plus(indentConfig.indent)
    }"}

